# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify, make_response
import jwt

app = Flask(__name__)

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    return parts[1]

@app.route('/proxy', methods=['GET', 'POST'])
def proxy():
    token = extract_token()
    if not token:
        response = jsonify({'error': 'Missing token'})
        response.status_code = 401
        return response

    try:
        claims = jwt.decode(token, options={"verify_signature": False})
    except Exception as e:
        response = jsonify({'error': str(e)})
        response.status_code = 403
        return response

    # Forward the request to the backend service with user claims
    backend_url = 'http://backend-service' + request.full_path
    headers = {
        **request.headers,
        'X-User-Claims': json.dumps(claims)
    }
    response = make_response(request.get(url=backend_url, headers=headers))
    
    return response

if __name__ == '__main__':
    app.run(debug=True)